def authenticate_credentials(self, key):
    model = self.get_model()
    try:
        token = model.objects.select_related('user').get(key=key)
    except model.DoesNotExist:
        raise exceptions.AuthenticationFailed(_('Invalid token.'))

    if not token.user.is_active:
        raise exceptions.AuthenticationFailed(_('User inactive or deleted.'))

    return (token.user, token)

def has_permission(self, request, view):
    if not request.user or (
       not request.user.is_authenticated and self.authenticated_users_only):
        return False

    # Workaround to ensure DjangoModelPermissions are not applied
    # to the root view when using DefaultRouter.
    if getattr(view, '_ignore_model_permissions', False):
        return True

    queryset = self._queryset(view)
    perms = self.get_required_permissions(request.method, queryset.model)

    return request.user.has_perms(perms)

def paginate_queryset(self, queryset, request, view=None):
    self.request = request
    self.limit = self.get_limit(request)
    if self.limit is None:
        return None

    self.count = self.get_count(queryset)
    self.offset = self.get_offset(request)
    if self.count > self.limit and self.template is not None:
        self.display_page_controls = True

    if self.count == 0 or self.offset > self.count:
        return []
    return list(queryset[self.offset:self.offset + self.limit])

def queryset(self, request, queryset):
        if not self.value():
            return queryset
        queries = [
            Q(hostname__icontains=self.value())
            | Q(ethernet_set__ipaddress__hostname__icontains=self.value())
        ]
        return queryset.filter(*queries).distinct()

def register(self, model_or_iterable, *args, **kwargs):
        super().register(model_or_iterable, *args, **kwargs)
        # operate on admin class instance to get processed extra views
        for model in model_or_iterable:
            if model._meta.swapped:
                continue
            admin_instance = self._registry[model]
            for view in self._get_views(admin_instance):
                view.post_register(self.name, model)

def __call__(
        self, request: HttpRequest
    ) -> HttpResponseBase | Awaitable[HttpResponseBase]:
        if self.async_mode:
            return self.__acall__(request)
        response: HttpResponseBase | None = self.check_preflight(request)
        if response is None:
            result = self.get_response(request)
            assert isinstance(result, HttpResponseBase)
            response = result
        self.add_response_headers(request, response)
        return response

def _get_perm_filter(
    perm: _PermType, model: Union[Model, type[Model], None] = None,
    ctype: Union[ContentType, None] = None
) -> Q:
    if isinstance(perm, Permission):
        return Q(permission=perm)

    assert ctype is not None or model is not None
    if ctype is None and model is not None:
        ctype = get_content_type(model)

    return Q(permission__codename=perm, permission__content_type=ctype)

def register(self, prefix, viewset, basename=None):
    if basename is None:
        basename = self.get_default_basename(viewset)

    if self.is_already_registered(basename):
        msg = (f'Router with basename "{basename}" is already registered. '
               f'Please provide a unique basename for viewset "{viewset}"')
        raise ImproperlyConfigured(msg)

    self.registry.append((prefix, viewset, basename))

    # invalidate the urls cache
    if hasattr(self, '_urls'):
        del self._urls

def serve_chain(page, request, args, kwargs):
