def value_from_datadict(self, data, files, name):
        value = data.get(name)
        if self.multi:
            if value:
                value = value.split(self.multivalue_separator)
            else:
                value = []
        return value

def filter_queryset(self, request, queryset, view):
        polymorphic_descendants = getattr(
            queryset.model, "_polymorphic_descendants", []
        )
        if polymorphic_descendants:
            ids, is_lookup_used = self._get_polymorphic_ids(
                queryset.model, polymorphic_descendants, request, view
            )
            if is_lookup_used:
                logger.debug("Applying PolymorphicDescendantsFilterBackend filters")
                queryset = queryset.filter(pk__in=list(ids))
        return queryset

def update(self, instance, validated_data):
        environments = validated_data.pop("environments", None)
        result = super().update(instance, validated_data)
        if environments is not None:
            self._save_environments(instance, environments)
        return result

def __init__(
        self,
        get_response: (
            Callable[[HttpRequest], HttpResponseBase]
            | Callable[[HttpRequest], Awaitable[HttpResponseBase]]
        ),
    ) -> None:
        self.get_response = get_response
        self.async_mode = iscoroutinefunction(self.get_response)

        if self.async_mode:
            # Mark the class as async-capable, but do the actual switch

            # inside __call__ to avoid swapping out dunder methods
            markcoroutinefunction(self)

def has_verified_email(user: AbstractBaseUser | None, email=None) -> bool:
    from .models import EmailAddress

    if not user:
        return False
    emailaddress = None
    if email:
        ret = False
        try:
            emailaddress = EmailAddress.objects.get_for_user(user, email)
            ret = emailaddress.verified
        except EmailAddress.DoesNotExist:
            pass
    else:
        ret = EmailAddress.objects.filter(user_id=user.pk, verified=True).exists()
    return ret

def create_token_if_necessary(user: BaseUser):
    from rest_framework.authtoken.models import Token
    token = Token.objects.filter(user=user).first()
    if token is not None:
        return token
    else:
        return Token.objects.create(user=user)

def process_exception(request: HttpRequest, exception):
        if isinstance(exception, ImmediateHttpResponse):
            return exception.response
        elif isinstance(exception, ReauthenticationRequired):
            redirect_url = reverse("account_login")
            methods = get_adapter().get_reauthentication_methods(request.user)
            if methods:
                redirect_url = methods[0]["url"]
            return flows.reauthentication.suspend_request(request, redirect_url)

