def custom_title_filter(title, base_class=FieldListFilter):
    class CustomTitledFilter(base_class):
        def __new__(cls, *args, **kwargs):
            filter_instance = base_class.create(*args, **kwargs)
            filter_instance.title = title
            return filter_instance

    return CustomTitledFilter

def _ajax_response(request: HttpRequest, response, form=None, data=None):
    adapter = get_adapter()
    if adapter.is_ajax(request):
        if isinstance(response, HttpResponseRedirect) or isinstance(
            response, HttpResponsePermanentRedirect
        ):
            redirect_to = response["Location"]
        else:
            redirect_to = None
        response = adapter.ajax_response(
            request, response, form=form, data=data, redirect_to=redirect_to
        )
    return response

def get_provider(self, request: HttpRequest | None = None):
        provider = getattr(self, "_provider", None)
        if provider:
            return provider
        adapter = get_adapter()
        provider = self._provider = adapter.get_provider(
            request or context.request, provider=self.provider
        )
        return provider

