def _check_assets_owner(instances, **kwargs):
    errors = {}
    requester = kwargs.get("requester", None)
    if not requester:
        return {"__all__": _("requester must be specified")}
    for instance in instances:
        if requester and instance.owner != requester:
            errors[instance] = _("requester is not an owner of the asset")
    return errors

def get_default_depreciation_rate(self, category=None):
        if category is None:
            category = self

        if category.default_depreciation_rate:
            return category.default_depreciation_rate
        elif category.parent:
            return self.get_default_depreciation_rate(category.parent)
        return 0

